-- --------------------------------------------------------

--
-- Struktura tabele `wp_posts`
--

CREATE TABLE `wp_posts` (
  `ID` bigint(20) UNSIGNED NOT NULL,
  `post_author` bigint(20) UNSIGNED NOT NULL DEFAULT 0,
  `post_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_date_gmt` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_content` longtext NOT NULL,
  `post_title` text NOT NULL,
  `post_excerpt` text NOT NULL,
  `post_status` varchar(20) NOT NULL DEFAULT 'publish',
  `comment_status` varchar(20) NOT NULL DEFAULT 'open',
  `ping_status` varchar(20) NOT NULL DEFAULT 'open',
  `post_password` varchar(255) NOT NULL DEFAULT '',
  `post_name` varchar(200) NOT NULL DEFAULT '',
  `to_ping` text NOT NULL,
  `pinged` text NOT NULL,
  `post_modified` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_modified_gmt` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_content_filtered` longtext NOT NULL,
  `post_parent` bigint(20) UNSIGNED NOT NULL DEFAULT 0,
  `guid` varchar(255) NOT NULL DEFAULT '',
  `menu_order` int(11) NOT NULL DEFAULT 0,
  `post_type` varchar(20) NOT NULL DEFAULT 'post',
  `post_mime_type` varchar(100) NOT NULL DEFAULT '',
  `comment_count` bigint(20) NOT NULL DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_520_ci;

--
-- Odloži podatke za tabelo `wp_posts`
--

INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(1, 1, '2026-05-08 20:31:01', '2026-05-08 19:31:01', '<!-- wp:paragraph -->\n<p>Dobrodošli v WordPressu. To je vaš prvi prispevek. Lahko ga uredite ali izbrišete, nato pričnete pisati!</p>\n<!-- /wp:paragraph -->', 'Pozdravljen svet!', '', 'trash', 'open', 'open', '', 'pozdravljen-svet__trashed', '', '', '2026-05-20 20:59:55', '2026-05-20 19:59:55', '', 0, 'http://localhost/trgovina/wordpress/?p=1', 0, 'post', '', 1),
(2, 1, '2026-05-08 20:31:01', '2026-05-08 19:31:01', '<!-- wp:paragraph -->\n<p>To je vzorčna stran. Drugačna je od prispevka bloga, ker bo ostala na mestu in se bo v večini tem prikazala v navigaciji spletišča. Večina ljudi začne s stranjo O meni, ki jih predstavi potencialnim obiskovalcem spletišča. V njej je lahko nekaj podobnega kot to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Pozdravljeni! Podnevi sem kolesarski kurir, ponoči ambiciozni igralec in to je moje spletišče. Živim v Los Angelesu, imam odličnega psa Jacka in rad imam pi&#241a Colado. (In pustim se ujeti v dežju.)</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>... ali nekaj takega:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Podjetje XYZ Doohickey Company je bila ustanovljena leta 1971 in od takrat javnosti ponuja kakovostne neimenovane izdelke. Nahaja se v Gotham Cityju, zaposluje več kot 2.000 ljudi in počne vse mogoče čudovite stvari za Gothamsko skupnost.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>Kot nov uporabnik WordPressa bi morali obiskati vašo <a href=\"http://localhost/trgovina/wordpress/wp-admin/\">nadzorno ploščo</a> za izbris te strani in ustvaritev novih strani za vašo vsebino. Zabavajte se!</p>\n<!-- /wp:paragraph -->', 'Vzorčna stran', '', 'trash', 'closed', 'open', '', 'vzorcna-stran__trashed', '', '', '2026-05-20 20:52:03', '2026-05-20 19:52:03', '', 0, 'http://localhost/trgovina/wordpress/?page_id=2', 0, 'page', '', 0),
(3, 1, '2026-05-08 20:31:01', '2026-05-08 19:31:01', '<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Kdo smo</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>Naš naslov spletišča je: http://localhost/trgovina/wordpress</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Komentarji</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>An anonymized string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service privacy policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Predstavnost</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Piškotki</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>If you leave a comment on our site you may opt-in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Vdelana vsebina iz drugih spletišč</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">S kom delimo vaše podatke</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>Če ste zahtevali ponastavitev gesla, bo v e-pošti za ponastavitev vključen vaš naslov IP.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Kako dolgo hranimo vaše podatke</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognize and approve any follow-up comments automatically instead of holding them in a moderation queue.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Katere pravice imate nad vašimi podatki</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Kam se pošiljajo vaši podatki</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Predlagano besedilo: </strong>Komentarji obiskovalcev se lahko preverijo s samodejno storitvijo za odkrivanje neželene vsebine.</p>\n<!-- /wp:paragraph -->\n', 'Pravilnik o zasebnosti', '', 'draft', 'closed', 'open', '', 'pravilnik-o-zasebnosti', '', '', '2026-05-08 20:31:01', '2026-05-08 19:31:01', '', 0, 'http://localhost/trgovina/wordpress/?page_id=3', 0, 'page', '', 0),
(4, 0, '2026-05-08 20:31:04', '2026-05-08 19:31:04', '<!-- wp:page-list /-->', 'Navigacija', '', 'publish', 'closed', 'closed', '', 'navigation', '', '', '2026-05-08 20:31:04', '2026-05-08 19:31:04', '', 0, 'http://localhost/trgovina/wordpress/2026/05/08/navigation/', 0, 'wp_navigation', '', 0),
