(20, 1, '2026-05-20 20:25:09', '2026-05-20 19:25:09', '', 'ryzen', '', 'inherit', 'open', 'closed', '', 'ryzen', '', '', '2026-05-20 20:25:09', '2026-05-20 19:25:09', '', 19, 'http://localhost/trgovina/wordpress/wp-content/uploads/2026/05/ryzen.png', 0, 'attachment', 'image/png', 0),
(21, 1, '2026-05-20 20:32:00', '2026-05-20 19:32:00', 'Grafična kartica nove generacije, namenjena igranju iger v visoki ločljivosti ter ustvarjanju grafičnih vsebin. Podpira ray tracing in DLSS tehnologijo za bolj realistično sliko in boljšo zmogljivost.', 'NVIDIA RTX 4060', 'Grafična kartica za igranje iger in ustvarjanje vsebin.', 'publish', 'open', 'closed', '', 'nvidia-rtx-4060', '', '', '2026-05-20 20:32:00', '2026-05-20 19:32:00', '', 0, 'http://localhost/trgovina/wordpress/?post_type=product&#038;p=21', 0, 'product', '', 0),
(22, 1, '2026-05-20 20:29:44', '2026-05-20 19:29:44', '', 'rtx', '', 'inherit', 'open', 'closed', '', 'rtx', '', '', '2026-05-20 20:29:44', '2026-05-20 19:29:44', '', 21, 'http://localhost/trgovina/wordpress/wp-content/uploads/2026/05/rtx.png', 0, 'attachment', 'image/png', 0),
(23, 1, '2026-05-20 20:35:50', '2026-05-20 19:35:50', 'Hiter DDR5 pomnilnik za sodobne računalnike, primeren za gaming in večopravilnost. Na voljo v različnih kapacitetah, ki omogočajo prilagoditev glede na potrebe uporabnika.', 'Kingston Fury 16GB DDR5', 'DDR5 pomnilnik za hitro in stabilno delovanje sistema.', 'publish', 'open', 'closed', '', 'kingston-fury-16gb-ddr5', '', '', '2026-05-20 20:35:50', '2026-05-20 19:35:50', '', 0, 'http://localhost/trgovina/wordpress/?post_type=product&#038;p=23', 0, 'product', '', 0),
(24, 1, '2026-05-20 20:35:37', '2026-05-20 19:35:37', '', 'fury', '', 'inherit', 'open', 'closed', '', 'fury', '', '', '2026-05-20 20:35:37', '2026-05-20 19:35:37', '', 23, 'http://localhost/trgovina/wordpress/wp-content/uploads/2026/05/fury.png', 0, 'attachment', 'image/png', 0),
(25, 1, '2026-05-20 20:38:59', '2026-05-20 19:38:59', 'Zanesljiv NVMe SSD disk z veliko hitrostjo branja in zapisovanja podatkov. Omogoča hitro nalaganje operacijskega sistema, programov in iger ter izboljša splošno odzivnost računalnika.', 'Samsung 970 EVO 1TB SSD', 'Hiter SSD disk za hitro nalaganje sistema in programov.', 'publish', 'open', 'closed', '', 'samsung-970-evo-1tb-ssd', '', '', '2026-05-20 20:39:00', '2026-05-20 19:39:00', '', 0, 'http://localhost/trgovina/wordpress/?post_type=product&#038;p=25', 0, 'product', '', 0),
(26, 1, '2026-05-20 20:37:29', '2026-05-20 19:37:29', '', 'evo', '', 'inherit', 'open', 'closed', '', 'evo', '', '', '2026-05-20 20:37:29', '2026-05-20 19:37:29', '', 25, 'http://localhost/trgovina/wordpress/wp-content/uploads/2026/05/evo.png', 0, 'attachment', 'image/png', 0),
(27, 1, '2026-05-20 20:41:06', '2026-05-20 19:41:06', 'Brezžična računalniška miška, namenjena produktivnosti in udobnemu delu. Ergonomska oblika ter natančen senzor omogočata učinkovito uporabo pri delu in vsakodnevnih opravilih.', 'Logitech MX Master 3', 'Ergonomska brezžična miška za udobno delo.', 'publish', 'open', 'closed', '', 'logitech-mx-master-3', '', '', '2026-05-20 20:41:07', '2026-05-20 19:41:07', '', 0, 'http://localhost/trgovina/wordpress/?post_type=product&#038;p=27', 0, 'product', '', 0),
(28, 1, '2026-05-20 20:40:33', '2026-05-20 19:40:33', '', 'mouse', '', 'inherit', 'open', 'closed', '', 'mouse', '', '', '2026-05-20 20:40:33', '2026-05-20 19:40:33', '', 27, 'http://localhost/trgovina/wordpress/wp-content/uploads/2026/05/mouse.png', 0, 'attachment', 'image/png', 0),
(29, 1, '2026-05-20 20:42:20', '2026-05-20 19:42:20', 'Gaming prenosnik z zmogljivo strojno opremo, namenjen igranju iger in zahtevnejšim opravilom. Na voljo v različnih konfiguracijah procesorjev ter opremljen z modernim hlajenjem in kakovostnim zaslonom.', 'ASUS ROG Strix Gaming', 'Gaming prenosnik za igre in zahtevnejša opravila.', 'publish', 'open', 'closed', '', 'asus-rog-strix-gaming', '', '', '2026-05-20 20:42:36', '2026-05-20 19:42:36', '', 0, 'http://localhost/trgovina/wordpress/?post_type=product&#038;p=29', 0, 'product', '', 0),
(30, 1, '2026-05-20 20:42:09', '2026-05-20 19:42:09', '', 'laptop', '', 'inherit', 'open', 'closed', '', 'laptop', '', '', '2026-05-20 20:42:09', '2026-05-20 19:42:09', '', 29, 'http://localhost/trgovina/wordpress/wp-content/uploads/2026/05/laptop.png', 0, 'attachment', 'image/png', 0),
(31, 1, '2026-05-20 20:43:11', '2026-05-20 19:43:11', '', '', '', 'draft', 'closed', 'closed', '', '', '', '', '2026-05-20 20:43:11', '2026-05-20 19:43:11', '', 0, 'http://localhost/trgovina/wordpress/?post_type=shop_order_placehold&p=31', 0, 'shop_order_placehold', '', 0),
(32, 1, '2026-05-20 20:52:03', '2026-05-20 19:52:03', '<!-- wp:paragraph -->\n<p>To je vzorčna stran. Drugačna je od prispevka bloga, ker bo ostala na mestu in se bo v večini tem prikazala v navigaciji spletišča. Večina ljudi začne s stranjo O meni, ki jih predstavi potencialnim obiskovalcem spletišča. V njej je lahko nekaj podobnega kot to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Pozdravljeni! Podnevi sem kolesarski kurir, ponoči ambiciozni igralec in to je moje spletišče. Živim v Los Angelesu, imam odličnega psa Jacka in rad imam pi&#241a Colado. (In pustim se ujeti v dežju.)</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>... ali nekaj takega:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Podjetje XYZ Doohickey Company je bila ustanovljena leta 1971 in od takrat javnosti ponuja kakovostne neimenovane izdelke. Nahaja se v Gotham Cityju, zaposluje več kot 2.000 ljudi in počne vse mogoče čudovite stvari za Gothamsko skupnost.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>Kot nov uporabnik WordPressa bi morali obiskati vašo <a href=\"http://localhost/trgovina/wordpress/wp-admin/\">nadzorno ploščo</a> za izbris te strani in ustvaritev novih strani za vašo vsebino. Zabavajte se!</p>\n<!-- /wp:paragraph -->', 'Vzorčna stran', '', 'inherit', 'closed', 'closed', '', '2-revision-v1', '', '', '2026-05-20 20:52:03', '2026-05-20 19:52:03', '', 2, 'http://localhost/trgovina/wordpress/?p=32', 0, 'revision', '', 0),
(33, 1, '2026-05-20 20:59:55', '2026-05-20 19:59:55', '<!-- wp:paragraph -->\n<p>Dobrodošli v WordPressu. To je vaš prvi prispevek. Lahko ga uredite ali izbrišete, nato pričnete pisati!</p>\n<!-- /wp:paragraph -->', 'Pozdravljen svet!', '', 'inherit', 'closed', 'closed', '', '1-revision-v1', '', '', '2026-05-20 20:59:55', '2026-05-20 19:59:55', '', 1, 'http://localhost/trgovina/wordpress/?p=33', 0, 'revision', '', 0);

